1	import { HttpModule } from '@nestjs/axios';
2	import { BullModule, InjectQueue } from '@nestjs/bullmq';
3	import { Module, OnModuleInit } from '@nestjs/common';
4	import { Queue } from 'bullmq';
5	
6	import { CacheModule } from '@modules/cache/cache.module';
7	import { DbModule } from '@modules/db/db.module';
8	import { EnvConfigModule } from '@modules/env-config/env-config.module';
9	import { JiraChangelogModel } from '@modules/jira/db/jira-changelog.model';
10	import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
11	import { JiraIssueModel } from '@modules/jira/db/jira-issues.model';
12	import { JiraProjectModel } from '@modules/jira/db/jira-projects.model';
13	import { JiraSprintModel } from '@modules/jira/db/jira-sprints.model';
14	import { JiraWorklogModel } from '@modules/jira/db/jira-worklogs.model';
15	import { JiraApiService } from '@modules/jira/jira-api.service';
16	import { JiraInstallService } from '@modules/jira/jira-install.service';
17	import { JiraProcessor } from '@modules/jira/jira-processor.service';
18	import { JiraSyncService } from '@modules/jira/jira-sync.service';
19	import { JiraController } from '@modules/jira/jira.controller';
20	
21	const TWELVE_HOURS_MS = 12 * 60 * 60 * 1000;
22	
23	@Module({
24		imports: [
25			HttpModule,
26			CacheModule,
27			DbModule,
28			EnvConfigModule,
29			BullModule.registerQueue({ name: 'jira' }),
30		],
31		controllers: [JiraController],
32		providers: [
33			JiraInstallationModel,
34			JiraProjectModel,
35			JiraIssueModel,
36			JiraChangelogModel,
37			JiraWorklogModel,
38			JiraSprintModel,
39			JiraApiService,
40			JiraInstallService,
41			JiraSyncService,
42			JiraProcessor,
43		],
44	})
45	export class JiraModule implements OnModuleInit {
46		constructor(@InjectQueue('jira') private readonly jiraQueue: Queue) {}
47	
48		async onModuleInit(): Promise<void> {
49			await this.jiraQueue.add(
50				'poll_installations',
51				{ triggeredAt: new Date().toISOString() },
52				{
53					repeat: { every: TWELVE_HOURS_MS },
54					jobId: 'poll_installations_cron',
55				},
56			);
57		}
58	}
