41			AuthModule,
42			UserModule,
43			CompanyModule,
44			CompanyMemberModule,
45			InvitationModule,
46			SessionModule,
47			GithubModule,
48			JiraModule,
49		],
50		controllers: [],
51		providers: [
52			{ provide: APP_GUARD, useClass: AuthGuard },
53			{ provide: APP_GUARD, useClass: RolesGuard },
54			{ provide: APP_GUARD, useClass: FastifyThrottlerGuard },
55		],
56	})
57	export class AppModule implements NestModule {
58		configure(consumer: MiddlewareConsumer): void {
59			consumer.apply(CorrelationIdMiddleware).forRoutes('*path');
60		}
61	}
